array_map(
			function ( $value ) {
				$value['crop'] = isset( $value['crop'] ) ?
					( is_array( $value['crop'] )
						? $value['crop'] :
						(bool) $value['crop'] )
					: false;

				return $value;
			},
			self::$image_sizes
		)

array_map(
			function ( $value ) {
				$parts = parse_url( $value );
				$domain = '';
				if ( isset( $parts['host'] ) ) {
					$domain = $parts['host'];
				} elseif ( isset( $parts['path'] ) ) {
					$domain = $parts['path'];
				}
				return $domain;
			},
			$urls
		)

usort(
			$conflict_list,
			function ( $item1, $item2 ) {
				if ( ! isset( $item1['severity'] ) ) {
					return -1;
				}
				if ( ! isset( $item2['severity'] ) ) {
					return -1;
				}
				$severity_map = [
					'high' => 0,
					'medium' => 1,
					'low' => 1,
				];

				if ( $severity_map[ $item1['severity'] ] === $severity_map[ $item2['severity'] ] ) {
					if ( ! isset( $item1['priority'] ) ) {
						return 0;
					}
					if ( ! isset( $item2['priority'] ) ) {
						return 0;
					}
					if ( $item1['priority'] === $item2['priority'] ) {
						return 0;
					}
					return $item1['priority'] < $item2['priority'] ? -1 : +1;
				}
				return $severity_map[ $item1['severity'] ] < $severity_map[ $item2['severity'] ] ? -1 : 1;
			}
		)

$wpdb->get_results(
			$wpdb->prepare(
                // phpcs:ignore WordPress.DB.PreparedSQL.InterpolatedNotPrepared -- This query cannot use interpolation.
				"SELECT post_id, meta_value FROM {$wpdb->postmeta} WHERE meta_key = %s AND meta_value IN ( {$meta_values_str} )",
				self::OM_DAM_IMPORTED_FLAG
			)
		)

array_filter(
			$extracted_urls,
			function ( $value ) use ( $slashed_config ) {
				return strpos( $value, Optml_Config::$service_url ) === false && strpos( $value, $slashed_config ) === false || Optml_Media_Offload::is_not_processed_image( $value ) || $this->tag_replacer->url_has_dam_flag( $value );
			}
		)

array_map(
			function ( $url ) use ( $upload_resource ) {
				$is_slashed  = strpos( $url, '\/' ) !== false;
				$is_relative = strpos(
					$url,
					$is_slashed ?
										addcslashes( $upload_resource['content_path'], '/' ) :
										$upload_resource['content_path']
				) === 0;
				if ( $is_relative ) {
					$url = $upload_resource['content_host'] . $url;
				}

				return apply_filters( 'optml_content_url', $url );
			},
			$urls
		)

array_filter(
				get_post_types(),
				function ( $post_type ) {
					if ( $post_type === 'attachment' || $post_type === 'revision' ) {
						return false;
					}

					return true;
				}
			)

array_filter(
			get_post_types(),
			function ( $post_type ) {
				if ( $post_type === 'attachment' || $post_type === 'revision' ) {
					return false;
				}

				return true;
			}
		)

array_map(
			function ( $image_id ) {
				$meta      = wp_get_attachment_metadata( $image_id );
				$extension = Optml_Media_Offload::instance()->get_ext( $meta['file'] );

				return str_replace( '.' . $extension, '', $meta['file'] );
			},
			$images
		)

array_filter(
					array_map( 'sanitize_url', array_values( $bg_urls ) ),
					function ( $url ) {
						// we ignore urls that are not from our service
						return strpos( $url, Optml_Config::$service_url ) === 0;
					}
				)

array_filter(
				array_map( 'sanitize_url', array_values( $lcp_data['u'] ?? [] ) ),
				function ( $url ) {
					// we ignore urls that are not from our service
					return strpos( $url, Optml_Config::$service_url ) === 0;
				}
			)

usort(
				$all_entries,
				function ( $a, $b ) {
					preg_match( '/(\d+)w/', $a, $matches_a );
					preg_match( '/(\d+)w/', $b, $matches_b );
					$width_a = isset( $matches_a[1] ) ? (int) $matches_a[1] : 0;
					$width_b = isset( $matches_b[1] ) ? (int) $matches_b[1] : 0;
					return $width_a - $width_b;
				}
			)

usort(
				$all_entries,
				function ( $a, $b ) {
					preg_match( '/max-width:\s*(\d+)px/', $a, $matches_a );
					preg_match( '/max-width:\s*(\d+)px/', $b, $matches_b );
					$breakpoint_a = isset( $matches_a[1] ) ? (int) $matches_a[1] : 0;
					$breakpoint_b = isset( $matches_b[1] ) ? (int) $matches_b[1] : 0;
					return $breakpoint_b - $breakpoint_a; // Descending order
				}
			)

array_filter(
			$attributes,
			function ( $key ) {
				return ! in_array( $key, array_keys( $this->block_attributes ), true ) && $key !== 'style';
			},
			ARRAY_FILTER_USE_KEY
		)

array_filter(
			$pages,
			function ( $page_data, $page_key ) use ( $product_pages ) {
				return in_array( $page_key, $product_pages, true ) &&
					   isset( $page_data['plugin']['status'] ) &&
					   $page_data['plugin']['status'] === 'not-installed';
			},
			ARRAY_FILTER_USE_BOTH
		)

array_filter(
					$plugins,
					function( $plugin ) {
						return ( is_object( $plugin ) && isset( $plugin->slug ) && $plugin->slug !== 'learning-management-system' ) ||
							( is_array( $plugin ) && isset( $plugin['slug'] ) && $plugin['slug'] !== 'learning-management-system' );
					}
				)

wp_remote_post(
				sprintf( '%slicense/%s/%s/%s', Product::API_URL, $action, rawurlencode( $this->product->get_name() ), $license ),
				array(
					'body'    => wp_json_encode(
						array(
							'url' => rawurlencode( home_url() ),
						)
					),
					'headers' => array(
						'Content-Type' => 'application/json',
					),
				)
			)

array_filter(
